#include <bits/stdc++.h>
using namespace std;
int n,v,e,a[31],b[31],ans=100000,sa,sb;//没骂人
void dfs(int x){
    if(++e>=2e8)
        return;
    if(sa+sb>=v)
        ans=min(ans,abs(sa-sb));
    for(int i=x+1;i<=n;i++){
        sa+=a[i],sb+=b[i];
        dfs(i);
        sa-=a[i],sb-=b[i];
    }
}
int main(){
    cin>>n>>v;
    for(int i=1;i<=n;i++)
        cin>>a[i]>>b[i];
    dfs(0);
    if(ans<100000)
        cout<<ans;
    else
        cout<<-1;
    return 0;
}
